#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38
#endif

#include <omp.h>

void
kmeans_kernel_c(float  *feature,   
				float  *clusters,
				int    *membership,
				int     npoints,
				int     nclusters,
				int     nfeatures,
				int		offset,
				int		size
			  ) 
{
	int point_id;
#pragma omp parallel for private(point_id)
	for (point_id = 0; point_id < npoints; point_id++)
	{
		int index = 0;
		float min_dist=FLT_MAX;
		int i, l;
		for (i=0; i < nclusters; i++) {
			float dist = 0;
			float ans  = 0;
			for (l=0; l<nfeatures; l++){
				float diff = feature[l * npoints + point_id] - clusters[i*nfeatures + l];
				ans += diff * diff;
			}
			dist = ans;
			if (dist < min_dist) {
				min_dist = dist;
				index    = i;
			}
		}
		membership[point_id] = index;
	}
}

void
kmeans_swap(float  *feature,   
			float  *feature_swap,
			int     npoints,
			int     nfeatures
){
	int tid;
#pragma omp parallel for private(tid)
	for (tid = 0; tid < npoints; tid++) {
		int i;
		for(i = 0; i <  nfeatures; i++)
			feature_swap[i * npoints + tid] = feature[tid * nfeatures + i];
	}
}
